    private void initProfileSection() {        // Si on n'est pas sur la page Compte, les champs sont absents
        if (profileFirstNameField == null) {
            return;
        }

        User current = SessionManager.getCurrentUser();
        if (current == null) {
            setProfileMessage("Aucun utilisateur connecté.", true);
            return;
        }

        profileFirstNameField.setText(current.getPrenom());
        profileLastNameField.setText(current.getNom());
        profilePhoneField.setText(current.getTelephoneUser());
        profileAddressField.setText(current.getAdresseUser());

        if (current.getDateNaissance() != null) {
            profileBirthDatePicker.setValue(current.getDateNaissance());
        }

        profileCinField.setText(current.getCin());
        profileCinField.setEditable(false);

        profileEmailField.setText(current.getEmailUser());
        profileEmailField.setEditable(false);

        updateAvatar(profileImageView, profileInitialsLabel, current);
        clearProfileValidationStyles();
        setProfileMessage("", false);

        // Live validation listeners
        profileFirstNameField.textProperty().addListener((obs, o, n) -> validateProfileFirstName());
        profileLastNameField.textProperty().addListener((obs, o, n) -> validateProfileLastName());
        profilePhoneField.textProperty().addListener((obs, o, n) -> validateProfilePhone());
        profileAddressField.textProperty().addListener((obs, o, n) -> validateProfileAddress());
        profileCinField.textProperty().addListener((obs, o, n) -> validateProfileCin());
        if (profileBirthDatePicker != null) {
            profileBirthDatePicker.valueProperty().addListener((obs, o, n) -> validateProfileBirthDate());
        }
    }

    private String buildInitials(String firstName, String lastName) {
        String f = firstName == null ? "" : firstName.trim();
        String l = lastName == null ? "" : lastName.trim();
        StringBuilder sb = new StringBuilder();
        if (!f.isEmpty()) sb.append(Character.toUpperCase(f.charAt(0)));
        if (!l.isEmpty()) sb.append(Character.toUpperCase(l.charAt(0)));
        String res = sb.toString();
        return res.isEmpty() ? "MF" : res;
    }

    private void updateAvatar(ImageView imageView, Label initialsLabel, User current) {
        if (imageView == null && initialsLabel == null) return;

        String picture = current.getProfilePicture();
        boolean hasImage = false;
        if (imageView != null && picture != null && !picture.isEmpty()) {
            try {
                File file = new File(picture);
                Image img = file.exists() ? new Image(file.toURI().toString(), false) : null;
                if (img != null) {
                    imageView.setImage(img);
                    hasImage = true;
                }
            } catch (Exception ignored) {
            }
        }

        if (initialsLabel != null) {
            if (!hasImage) {
                String initials = buildInitials(current.getPrenom(), current.getNom());
                initialsLabel.setText(initials);
                initialsLabel.setVisible(true);
            } else {
                initialsLabel.setVisible(false);
            }
        }
    }

    private void initSidebarUserInfo() {
        // Si on n'est pas dans un contexte avec sidebar, les champs sont absents
        if (sidebarNameLabel == null && sidebarProfileImage == null) {
            return;
        }

        User current = SessionManager.getCurrentUser();
        if (current == null) {
            if (sidebarNameLabel != null) {
                sidebarNameLabel.setText("Invité");
            }
            if (sidebarRoleLabel != null) {
                sidebarRoleLabel.setText("");
            }
            return;
        }

        if (sidebarNameLabel != null) {
            String prenom = current.getPrenom() == null ? "" : current.getPrenom().trim();
            String nom = current.getNom() == null ? "" : current.getNom().trim();
            String fullName = (prenom + " " + nom).trim();
            if (fullName.isEmpty()) {
                fullName = current.getEmailUser() != null ? current.getEmailUser() : "Utilisateur MedFlow";
            }
            sidebarNameLabel.setText(fullName);
        }

        if (sidebarRoleLabel != null) {
            sidebarRoleLabel.setText(buildDisplayRole(current));
        }

        updateAvatar(sidebarProfileImage, sidebarInitialsLabel, current);
    }

    private void initSidebarCardFlip() {
        if (sidebarCard == null || sidebarCardFront == null || sidebarCardBack == null) {
            return;
        }

        sidebarCardBack.setVisible(false);
        sidebarCardBack.setManaged(false);
        sidebarCardShowingBack = false;

        sidebarCard.setOnMouseEntered(e -> {
            if (!sidebarCardShowingBack && !sidebarCardAnimating) {
                flipCard(true);
            }
        });
        sidebarCard.setOnMouseExited(e -> {
            if (sidebarCardShowingBack && !sidebarCardAnimating) {
                flipCard(false);
            }
        });
    }

    private void flipCard(boolean toBack) {
        if (sidebarCard == null || sidebarCardFront == null || sidebarCardBack == null) return;

        if (sidebarCardAnimating) return;
        sidebarCardAnimating = true;

        Node first = toBack ? sidebarCardFront : sidebarCardBack;
        Node second = toBack ? sidebarCardBack : sidebarCardFront;

        RotateTransition rt1 = new RotateTransition(Duration.millis(160), sidebarCard);
        rt1.setAxis(Rotate.Y_AXIS);
        rt1.setFromAngle(0);
        rt1.setToAngle(90);
        rt1.setOnFinished(ev -> {
            first.setVisible(false);
            first.setManaged(false);
            second.setVisible(true);
            second.setManaged(true);
            sidebarCardShowingBack = toBack;

            RotateTransition rt2 = new RotateTransition(Duration.millis(160), sidebarCard);
            rt2.setAxis(Rotate.Y_AXIS);
            rt2.setFromAngle(-90);
            rt2.setToAngle(0);
            rt2.setOnFinished(e2 -> sidebarCardAnimating = false);
            rt2.play();
        });
        rt1.play();
    }

    private String buildDisplayRole(User current) {
        String role = current.getRoleSysteme();
        String type = current.getTypeStaff();
        if (role != null) role = role.trim().toUpperCase();
        if (type != null) type = type.trim().toUpperCase();

        if (role == null || role.isBlank() || "PATIENT".equals(role)) {
            return "Patient";
        }
        if ("ADMIN".equals(role)) {
            return "Administrateur";
        }
        if ("STAFF".equals(role)) {
            if ("RESP_EVEN".equals(type)) return "Resp. événements";
            if ("RESP_PRODUCTS".equals(type)) return "Resp. produits";
            if ("RESP_BLOG".equals(type) || "RESP_RECLAMATION".equals(type)) return "Resp. réclamations/blog";
            if ("RESP_PATIENTS".equals(type)) return "Resp. patients";
            if ("RESP_USERS".equals(type)) return "Resp. utilisateurs";
            return "Staff";
        }
        return role;
    }

    // ══════════════════════════════════════════════════════════════════════════
    //  Section TOTP (page Compte)
    // ══════════════════════════════════════════════════════════════════════════

    private void initTotpSection() {
        if (totpStatusLabel == null) return; // pas sur la page Compte
        User current = SessionManager.getCurrentUser();
        if (current == null) return;

        // Recharger les donnees TOTP depuis la DB
        userService.enrichTotpData(current);
        SessionManager.setCurrentUser(current);

        refreshTotpUi(current);
    }

    private void refreshTotpUi(User user) {
        if (totpStatusLabel == null) return;
        boolean isAdminOrStaff = user != null && ("ADMIN".equalsIgnoreCase(user.getRoleSysteme())
                || "STAFF".equalsIgnoreCase(user.getRoleSysteme())
                || user.getTypeStaff() != null);

        if (user == null || !isAdminOrStaff) {
            totpStatusLabel.setText("⚪  TOTP disponible uniquement pour les admins et le staff.");
            totpStatusLabel.setStyle("-fx-text-fill: #64748b;");
            if (totpToggleButton != null) {
                totpToggleButton.setDisable(true);
                totpToggleButton.setText("Non disponible");
            }
            return;
        }

        if (user.isTotpEnabled()) {
            totpStatusLabel.setText("  TOTP actif — votre compte est protege par 2FA.");
            totpStatusLabel.setStyle("-fx-text-fill: #16a34a; -fx-font-weight: 700;");
            if (totpToggleButton != null) {
                totpToggleButton.setText("Desactiver le TOTP");
                totpToggleButton.setDisable(false);
            }
        } else {
            totpStatusLabel.setText("  TOTP inactif — aucune double authentification.");
            totpStatusLabel.setStyle("-fx-text-fill: #dc2626;");
            if (totpToggleButton != null) {
                totpToggleButton.setText("Activer le TOTP");
                totpToggleButton.setDisable(false);
            }
        }
    }

    @FXML
    private void handleSetupTotp(ActionEvent event) {
        User current = SessionManager.getCurrentUser();
        if (current == null) return;

        userService.enrichTotpData(current);

        if (current.isTotpEnabled()) {
            showTotpDisableDialog(current);
        } else {
            showTotpEnableDialog(current);
        }
        refreshTotpUi(current);
    }

    // ── Dialogue d'activation TOTP ──────────────────────────────────────────

    private void showTotpEnableDialog(User user) {
        String newSecret = TotpService.generateSecret();
        String email     = user.getEmailUser() == null ? "user" : user.getEmailUser();
        String otpUri    = TotpService.getOtpAuthUri(newSecret, email);

        Dialog<Void> dialog = new Dialog<>();
        dialog.setTitle("Activer la double authentification");
        dialog.setHeaderText(null);
        styleTotpDialog(dialog);

        ButtonType enableBtn = new ButtonType("Activer", javafx.scene.control.ButtonBar.ButtonData.OK_DONE);
        ButtonType cancelBtn = new ButtonType("Annuler", javafx.scene.control.ButtonBar.ButtonData.CANCEL_CLOSE);
        dialog.getDialogPane().getButtonTypes().addAll(enableBtn, cancelBtn);
        styleTotpDialogButtons(dialog, enableBtn, cancelBtn);

        javafx.scene.layout.VBox content = new javafx.scene.layout.VBox(14);
        content.setStyle("-fx-padding: 18 28 12 28;");

        Label titleLbl = new Label("Scannez le QR code ou entrez la cle manuellement");
        titleLbl.setStyle("-fx-font-size: 13px; -fx-font-weight: 700; -fx-text-fill: #1e1b4b;");

        // QR code image
        javafx.scene.image.ImageView qrView = new javafx.scene.image.ImageView();
        qrView.setFitWidth(210); qrView.setFitHeight(210); qrView.setPreserveRatio(true);
        try {
            BufferedImage buffered = TotpService.generateQrCodeImage(otpUri, 210);
            javafx.scene.image.WritableImage fxImg = new javafx.scene.image.WritableImage(210, 210);
            javafx.embed.swing.SwingFXUtils.toFXImage(buffered, fxImg);
            qrView.setImage(fxImg);
        } catch (Exception ex) {
            System.err.println("[TOTP] Erreur generation QR: " + ex.getMessage());
        }

        javafx.scene.layout.HBox qrBox = new javafx.scene.layout.HBox(qrView);
        qrBox.setAlignment(javafx.geometry.Pos.CENTER);

        Label secretTitle = new Label("Cle secrete (saisie manuelle) :");
        secretTitle.setStyle("-fx-font-size: 11px; -fx-text-fill: #64748b;");

        TextField secretField = new TextField(newSecret);
        secretField.setEditable(false);
        secretField.setStyle(
                "-fx-font-family: 'Courier New', monospace; -fx-font-size: 13px; -fx-font-weight: 700;"
                + "-fx-background-color: #f1f5f9; -fx-border-color: #cbd5e1;"
                + "-fx-border-radius: 8; -fx-background-radius: 8; -fx-padding: 8 12;"
        );
        secretField.setMaxWidth(400);

        Label hint = new Label("1. Ouvrez Google Authenticator / Aegis  2. Scannez le QR code  3. Saisissez le code genere ci-dessous");
        hint.setWrapText(true);
        hint.setStyle("-fx-font-size: 11px; -fx-text-fill: #475569;");
        hint.setMaxWidth(420);

        Label codeLabel = new Label("Code de verification (6 chiffres) :");
        codeLabel.setStyle("-fx-font-size: 12px; -fx-font-weight: 600; -fx-text-fill: #334155;");

        TextField codeField = new TextField();
        codeField.setPromptText("000000");
        codeField.setMaxWidth(160);
        codeField.setStyle(
                "-fx-font-size: 22px; -fx-font-weight: 800; -fx-alignment: center;"
                + "-fx-background-color: #f5f3ff; -fx-border-color: #7c3aed;"
                + "-fx-border-radius: 10; -fx-background-radius: 10; -fx-padding: 8 12;"
        );
        codeField.textProperty().addListener((obs, o, n) -> {
            if (n == null) return;
            String d = n.replaceAll("[^\\d]", "");
            if (d.length() > 6) d = d.substring(0, 6);
            if (!d.equals(n)) codeField.setText(d);
        });

        Label errorLbl = new Label();
        errorLbl.setStyle("-fx-text-fill: #dc2626; -fx-font-size: 12px; -fx-font-weight: 600;");
        errorLbl.setVisible(false); errorLbl.setManaged(false);

        content.getChildren().addAll(titleLbl, qrBox, secretTitle, secretField, hint, codeLabel, codeField, errorLbl);
        dialog.getDialogPane().setContent(content);
        dialog.getDialogPane().setPrefWidth(480);

        // Bloquer activation si code pas a 6 chiffres
        javafx.scene.Node enableNode = dialog.getDialogPane().lookupButton(enableBtn);
        enableNode.setDisable(true);
        codeField.textProperty().addListener((obs, o, n) ->
                enableNode.setDisable(n == null || n.length() != 6));

        enableNode.addEventFilter(javafx.event.ActionEvent.ACTION, e -> {
            if (!TotpService.verifyCode(newSecret, codeField.getText().trim())) {
                e.consume();
                errorLbl.setText("Code incorrect. Verifiez l'heure de votre telephone et reessayez.");
                errorLbl.setVisible(true); errorLbl.setManaged(true);
            } else {
                // Sauvegarder en DB
                boolean saved = userService.enableTotp(user.getId(), newSecret);
                if (!saved) {
                    e.consume();
                    errorLbl.setText("Erreur lors de l'enregistrement. Reessayez.");
                    errorLbl.setVisible(true); errorLbl.setManaged(true);
                } else {
                    user.setTotpSecret(newSecret);
                    user.setTotpEnabled(true);
                    SessionManager.setCurrentUser(user);
                }
            }
        });

        dialog.setResultConverter(btn -> null);
        dialog.showAndWait();
    }

    // ── Dialogue de desactivation TOTP ──────────────────────────────────────

    private void showTotpDisableDialog(User user) {
        Dialog<Void> dialog = new Dialog<>();
        dialog.setTitle("Desactiver la double authentification");
        dialog.setHeaderText(null);
        styleTotpDialog(dialog);

        ButtonType disableBtn = new ButtonType("Desactiver", javafx.scene.control.ButtonBar.ButtonData.OK_DONE);
        ButtonType cancelBtn  = new ButtonType("Annuler",    javafx.scene.control.ButtonBar.ButtonData.CANCEL_CLOSE);
        dialog.getDialogPane().getButtonTypes().addAll(disableBtn, cancelBtn);
        styleTotpDialogButtons(dialog, disableBtn, cancelBtn);

        javafx.scene.layout.VBox content = new javafx.scene.layout.VBox(12);
        content.setStyle("-fx-padding: 20 28 12 28;");

        Label icon = new Label("⚠️");
        icon.setStyle("-fx-font-size: 36px;");

        Label title = new Label("Desactiver le TOTP ?");
        title.setStyle("-fx-font-size: 15px; -fx-font-weight: 800; -fx-text-fill: #991b1b;");

        Label msg = new Label("Cette action supprimera la protection 2FA de votre compte.\nConfirmez avec votre code actuel.");
        msg.setWrapText(true);
        msg.setStyle("-fx-font-size: 12px; -fx-text-fill: #475569;");

        Label codeLabel = new Label("Code actuel (6 chiffres) :");
        codeLabel.setStyle("-fx-font-size: 12px; -fx-font-weight: 600; -fx-text-fill: #334155;");

        TextField codeField = new TextField();
        codeField.setPromptText("000000");
        codeField.setMaxWidth(160);
        codeField.setStyle(
                "-fx-font-size: 22px; -fx-font-weight: 800; -fx-alignment: center;"
                + "-fx-background-color: #fff1f2; -fx-border-color: #dc2626;"
                + "-fx-border-radius: 10; -fx-background-radius: 10; -fx-padding: 8 12;"
        );
        codeField.textProperty().addListener((obs, o, n) -> {
            if (n == null) return;
            String d = n.replaceAll("[^\\d]", "");
            if (d.length() > 6) d = d.substring(0, 6);
            if (!d.equals(n)) codeField.setText(d);
        });

        Label errorLbl = new Label();
        errorLbl.setStyle("-fx-text-fill: #dc2626; -fx-font-size: 12px; -fx-font-weight: 600;");
        errorLbl.setVisible(false); errorLbl.setManaged(false);

        content.getChildren().addAll(icon, title, msg, codeLabel, codeField, errorLbl);
        dialog.getDialogPane().setContent(content);
        dialog.getDialogPane().setPrefWidth(420);

        javafx.scene.Node disableNode = dialog.getDialogPane().lookupButton(disableBtn);
        disableNode.setDisable(true);
        codeField.textProperty().addListener((obs, o, n) ->
                disableNode.setDisable(n == null || n.length() != 6));

        disableNode.addEventFilter(javafx.event.ActionEvent.ACTION, e -> {
            if (!TotpService.verifyCode(user.getTotpSecret(), codeField.getText().trim())) {
                e.consume();
                errorLbl.setText("Code invalide.");
                errorLbl.setVisible(true); errorLbl.setManaged(true);
            } else {
                boolean ok = userService.disableTotp(user.getId());
                if (!ok) {
                    e.consume();
                    errorLbl.setText("Erreur lors de la desactivation. Reessayez.");
                    errorLbl.setVisible(true); errorLbl.setManaged(true);
                } else {
                    user.setTotpEnabled(false);
                    user.setTotpSecret(null);
                    SessionManager.setCurrentUser(user);
                }
            }
        });

        dialog.setResultConverter(btn -> null);
        dialog.showAndWait();
    }

    // ── Helpers style dialogues TOTP ─────────────────────────────────────────

    private void styleTotpDialog(Dialog<?> dialog) {
        if (dialog == null || dialog.getDialogPane() == null) return;
        dialog.getDialogPane().setStyle(
                "-fx-background-color: linear-gradient(to bottom, #f8f7ff, #ffffff);"
                + "-fx-border-color: #7c3aed44; -fx-border-width: 1;"
                + "-fx-border-radius: 14; -fx-background-radius: 14; -fx-padding: 8;"
        );
    }

    private void styleTotpDialogButtons(Dialog<?> dialog,
                                        javafx.scene.control.ButtonType primaryBtn,
                                        javafx.scene.control.ButtonType secondaryBtn) {
        javafx.scene.Node primary   = dialog.getDialogPane().lookupButton(primaryBtn);
        javafx.scene.Node secondary = dialog.getDialogPane().lookupButton(secondaryBtn);
        if (primary != null) primary.setStyle(
                "-fx-background-color: #7c3aed; -fx-text-fill: white; -fx-font-weight: 700;"
                + "-fx-background-radius: 10; -fx-padding: 8 18;");
        if (secondary != null) secondary.setStyle(
                "-fx-background-color: #e2e8f0; -fx-text-fill: #0f172a; -fx-font-weight: 700;"
                + "-fx-background-radius: 10; -fx-padding: 8 18;");
    }

    private void navigate(ActionEvent event, String fxml, String title) {
        try {
            FXMLLoader loader = new FXMLLoader(getClass().getResource(fxml));
            Parent root = loader.load();
            Stage stage = (Stage) ((Node) event.getSource()).getScene().getWindow();
            stage.setScene(new Scene(root, 1400, 820));
            stage.setTitle(title);
            stage.setMaximized(true);
            stage.show();
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private void applyRolePermissions() {
        User current = SessionManager.getCurrentUser();
        if (current == null) {
            return;
        }

        String role = current.getRoleSysteme();
        String typeStaff = current.getTypeStaff();
        if (role != null) {
            role = role.trim().toUpperCase();
        }
        if (typeStaff != null) {
            typeStaff = typeStaff.trim().toUpperCase();
        }

        // Front sidebar :
        // - ADMIN : accès complet
        // - PATIENT : accès complet au front uniquement
        // - STAFF (RESP_EVEN, etc.) : accès complet au front + leur back-office dédié
        // Donc on ne restreint pas le menu ici.
        if ("ADMIN".equals(role) || "PATIENT".equals(role) || "STAFF".equals(role)) {
            return;
        }
    }

    private void restrictTo(Button... allowed) {
        Button[] all = new Button[]{
                accueilButton,
                reclamationButton,
                blogButton,
                pharmacieButton,
                evenementButton,
                consultationButton,
                compteButton
        };

        for (Button b : all) {
            if (b == null) continue;
            boolean isAllowed = false;
            for (Button ab : allowed) {
                if (b == ab) {
                    isAllowed = true;
                    break;
                }
            }
            if (!isAllowed) {
                b.setDisable(true);
                b.setVisible(false);
                b.setManaged(false);
            }
        }
    }

    private void setProfileMessage(String message, boolean error) {
        if (profileMessageLabel == null) return;
        profileMessageLabel.setText(message == null ? "" : message);
        if (message == null || message.isEmpty()) {
            profileMessageLabel.setStyle("");
        } else {
            String color = error ? "#dc2626" : "#16a34a";
            profileMessageLabel.setStyle("-fx-text-fill: " + color + "; -fx-font-size: 12px; -fx-font-weight: bold;");
        }
    }

