    //  TOTP 2FA
    // ══════════════════════════════════════════════════════════════════════════

    /**
     * Active le TOTP pour un utilisateur en sauvegardant son secret.
     */
    public boolean enableTotp(int userId, String totpSecret) {
        String snakeSql = "UPDATE user SET totp_secret = ?, totp_enabled = 1 WHERE id = ?";
        String camelSql = "UPDATE user SET totpSecret = ?, totpEnabled = 1 WHERE id = ?";
        for (String sql : new String[]{snakeSql, camelSql}) {
            try (PreparedStatement ps = cnx.prepareStatement(sql)) {
                ps.setString(1, totpSecret);
                ps.setInt(2, userId);
                if (ps.executeUpdate() > 0) return true;
            } catch (SQLException ignored) {}
        }
        return false;
    }

    /**
     * Desactive le TOTP et efface le secret.
     */
    public boolean disableTotp(int userId) {
        String snakeSql = "UPDATE user SET totp_secret = NULL, totp_enabled = 0 WHERE id = ?";
        String camelSql = "UPDATE user SET totpSecret = NULL, totpEnabled = 0 WHERE id = ?";
        for (String sql : new String[]{snakeSql, camelSql}) {
            try (PreparedStatement ps = cnx.prepareStatement(sql)) {
                ps.setInt(1, userId);
                if (ps.executeUpdate() > 0) return true;
            } catch (SQLException ignored) {}
        }
        return false;
    }

    /**
     * Charge les champs TOTP depuis la DB et les injecte dans le User.
     */
    public void enrichTotpData(User user) {
        if (user == null) return;
        String snakeSql = "SELECT totp_secret, totp_enabled FROM user WHERE id = ?";
        String camelSql = "SELECT totpSecret AS totp_secret, totpEnabled AS totp_enabled FROM user WHERE id = ?";
        for (String sql : new String[]{snakeSql, camelSql}) {
            try (PreparedStatement ps = cnx.prepareStatement(sql)) {
                ps.setInt(1, user.getId());
                try (ResultSet rs = ps.executeQuery()) {
                    if (rs.next()) {
                        user.setTotpSecret(rs.getString("totp_secret"));
                        user.setTotpEnabled(rs.getBoolean("totp_enabled"));
                        return;
                    }
                }
            } catch (SQLException ignored) {}
        }
    }

    public List<User> getStaffByRoleAndType(String roleSysteme, String typeStaff) {
        List<User> users = new ArrayList<>();

        String querySnakeCase = "SELECT id, nom, prenom, role_systeme, type_staff FROM user WHERE role_systeme = ? AND type_staff = ? ORDER BY nom, prenom";
        String queryCamelCase = "SELECT id, nom, prenom, roleSysteme, typeStaff FROM user WHERE roleSysteme = ? AND typeStaff = ? ORDER BY nom, prenom";

        boolean loaded = loadUsersWithQuery(users, querySnakeCase, roleSysteme, typeStaff, "role_systeme", "type_staff");
        if (!loaded) {
            loadUsersWithQuery(users, queryCamelCase, roleSysteme, typeStaff, "roleSysteme", "typeStaff");
        }

        return users;
    }

    private boolean loadUsersWithQuery(
            List<User> target,
            String sql,
            String roleSysteme,
            String typeStaff,
            String roleColumn,
            String typeColumn
    ) {
        try (PreparedStatement ps = cnx.prepareStatement(sql)) {
            ps.setString(1, roleSysteme);
            ps.setString(2, typeStaff);

            try (ResultSet rs = ps.executeQuery()) {
                while (rs.next()) {
                    User user = new User();
                    user.setId(rs.getInt("id"));
                    user.setNom(rs.getString("nom"));
                    user.setPrenom(rs.getString("prenom"));
                    user.setRoleSysteme(rs.getString(roleColumn));
                    user.setTypeStaff(rs.getString(typeColumn));
                    target.add(user);
                }
            }
            return true;
        } catch (SQLException e) {
            return false;
        }
    }

